                        CLAY_TEXT(CLAY_STRING("Line Height"), infoTitleConfig);
                        CLAY_TEXT(textConfig->lineHeight == 0 ? CLAY_STRING("auto") : Clay__IntToString(textConfig->lineHeight), infoTextConfig);
                        // .letterSpacing
